     5→  AUTH = 'AUTH',
     6→  CONTRIBUTE = 'CONTRIBUTE',
     7→  PROFILE = 'PROFILE',
     8→  ANALYTICS = 'ANALYTICS',
     9→  SETTINGS = 'SETTINGS',
