   610→    }
   611→
   612→    const primaryPhotoFraud = buildPhotoFraudMetadata({
   613→      extracted: primaryPhotoMetadata,
   614→      submissionLocation: location,
   615→      ipLocation,
   616→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
   617→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
   618→    });
   619→    const secondaryPhotoFraud = buildPhotoFraudMetadata({
   620→      extracted: secondaryPhotoMetadata,
   621→      submissionLocation: location,
   622→      ipLocation,
   623→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
   624→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
   625→    });
   626→    details.fraudCheck = buildSubmissionFraudCheck({
   627→      submissionLocation: location,
   628→      effectiveLocation: finalLocation,
   629→      ipLocation,
   630→      primaryPhoto: primaryPhotoFraud,
   631→      secondaryPhoto: secondaryPhotoFraud,
   632→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
   633→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
