   155→async function signInWithCredentialsOnce(identifier: string, password: string): Promise<void> {
   156→  const normalizedIdentifier = normalizeIdentifier(identifier)?.value ?? identifier.trim();
   157→  const csrfToken = await getCsrfToken();
   158→  const body = new URLSearchParams();
   159→  body.set("csrfToken", csrfToken);
   160→  body.set("identifier", normalizedIdentifier);
   161→  body.set("email", normalizedIdentifier);
   162→  body.set("password", password);
   163→  body.set("callbackUrl", window.location.origin);
   164→  body.set("json", "true");
   165→
   166→  const response = await apiFetch("/api/auth/callback/credentials", {
   167→    method: "POST",
   168→    headers: {
   169→      "Content-Type": "application/x-www-form-urlencoded",
   170→      "X-Auth-Return-Redirect": "1",
   171→    },
   172→    body,
   173→  });
   174→
   175→  if (!response.ok) {
   176→    const { message } = await extractResponseErrorPayload(response, DEFAULT_SIGN_IN_ERROR);
   177→    const retryable = response.status >= 500;
   178→    throw new AuthClientError(retryable ? "auth_unavailable" : "request_error", message, { retryable });
   179→  }
   180→
   181→  const payload = await safeReadJson<AuthRedirectPayload>(response);
   182→  if (!payload || typeof payload.url !== "string") {
   183→    throw new AuthClientError("unknown_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
   184→  }
