   186→  let url: URL;
   187→  try {
   188→    url = new URL(payload.url, window.location.origin);
   189→  } catch {
   190→    throw new AuthClientError("unknown_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
   191→  }
   192→
   193→  const errorType = url.searchParams.get("error");
   194→  const errorCode = url.searchParams.get("code");
   195→  if (errorType || errorCode) {
   196→    throw mapAuthJsError(errorType, errorCode);
   197→  }
   198→}
