    83→export function haversineKm(a: SubmissionLocation, b: SubmissionLocation): number {
    84→  const toRad = (deg: number) => (deg * Math.PI) / 180;
    85→  const dLat = toRad(b.latitude - a.latitude);
    86→  const dLon = toRad(b.longitude - a.longitude);
    87→  const lat1 = toRad(a.latitude);
    88→  const lat2 = toRad(b.latitude);
    89→  const sinLat = Math.sin(dLat / 2);
    90→  const sinLon = Math.sin(dLon / 2);
    91→  const h = sinLat * sinLat + Math.cos(lat1) * Math.cos(lat2) * sinLon * sinLon;
    92→  return 2 * EARTH_RADIUS_KM * Math.atan2(Math.sqrt(h), Math.sqrt(1 - h));
    93→}
