    95→async function putItem(item: QueueItem): Promise<void> {
    96→  const db = await openDb();
    97→  const tx = db.transaction(STORE_NAME, 'readwrite');
    98→  tx.objectStore(STORE_NAME).put(item);
    99→  await transactionDone(tx);
   100→  db.close();
   101→}
