   116→
   117→export async function listQueueItems(): Promise<QueueItem[]> {
   118→  const db = await openDb();
   119→  const tx = db.transaction(STORE_NAME, 'readonly');
   120→  const request = tx.objectStore(STORE_NAME).getAll();
   121→  const result = await requestToPromise(request);
   122→  await transactionDone(tx);
   123→  db.close();
   124→  return (result as QueueItem[]).sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
   125→}
   126→
   127→async function updateItem(id: string, updater: (item: QueueItem) => QueueItem): Promise<QueueItem | null> {
   128→  const db = await openDb();
   129→  return await new Promise<QueueItem | null>((resolve, reject) => {
   130→    const tx = db.transaction(STORE_NAME, 'readwrite');
   131→    const store = tx.objectStore(STORE_NAME);
   132→    let updated: QueueItem | null = null;
   133→    const getRequest = store.get(id);
   134→    getRequest.onsuccess = () => {
   135→      const existing = getRequest.result as QueueItem | undefined;
   136→      if (!existing) return;
   137→      updated = updater(existing);
   138→      store.put(updated);
   139→    };
   140→    getRequest.onerror = () => reject(getRequest.error);
   141→    tx.oncomplete = () => {
   142→      db.close();
   143→      resolve(updated);
   144→    };
   145→    tx.onerror = () => {
   146→      db.close();
   147→      reject(tx.error);
   148→    };
   149→    tx.onabort = () => {
   150→      db.close();
   151→      reject(tx.error ?? new Error('IndexedDB transaction aborted'));
   152→    };
   153→  });
   154→}
