   190→export async function getQueueStats(): Promise<{ pending: number; failed: number; total: number }> {
   191→  const items = await listQueueItems();
   192→  return {
   193→    pending: items.filter((item) => item.status === 'pending' || item.status === 'syncing').length,
   194→    failed: items.filter((item) => item.status === 'failed').length,
   195→    total: items.length
   196→  };
   197→}
   198→
   199→export async function flushOfflineQueue(sendFn: (payload: SubmissionInput) => Promise<void>): Promise<QueueSyncSummary> {
   200→  const items = await listQueueItems();
   201→  let synced = 0;
   202→  let failed = 0;
   203→  const syncedIds: string[] = [];
   204→  const failedIds: string[] = [];
   205→  let permanentFailures = 0;
   206→  const permanentFailureIds: string[] = [];
   207→  const permanentFailureMessages = new Set<string>();
   208→
   209→  for (const item of items) {
   210→    await updateItem(item.id, (current) => ({
   211→      ...current,
   212→      status: 'syncing',
   213→      attempts: current.attempts + 1,
   214→      updatedAt: new Date().toISOString()
   215→    }));
   216→
   217→    try {
   218→      await sendFn(item.payload);
   219→      await removeItem(item.id);
   220→      synced += 1;
   221→      syncedIds.push(item.id);
   222→    } catch (error) {
   223→      const details = toQueueErrorInfo(error);
   224→      if (details.retryable) {
   225→        failed += 1;
   226→        failedIds.push(item.id);
   227→        await updateItem(item.id, (current) => ({
   228→          ...current,
   229→          status: 'failed',
   230→          updatedAt: new Date().toISOString(),
   231→          lastError: details.message,
   232→        }));
   233→        continue;
   234→      }
   235→
   236→      permanentFailures += 1;
   237→      permanentFailureIds.push(item.id);
   238→      permanentFailureMessages.add(details.message);
   239→      await putSyncErrorRecord({
   240→        id: crypto.randomUUID(),
   241→        queueItemId: item.id,
   242→        message: details.message,
   243→        createdAt: new Date().toISOString(),
   244→        payloadSummary: {
   245→          eventType: item.payload.eventType,
   246→          category: item.payload.category,
   247→          pointId: item.payload.pointId,
   248→          location: item.payload.location,
   249→        },
   250→      });
   251→      await removeItem(item.id);
   252→    }
   253→  }
   254→
   255→  const remaining = (await listQueueItems()).length;
   256→  return {
   257→    synced,
   258→    failed,
   259→    syncedIds,
   260→    failedIds,
   261→    permanentFailures,
   262→    permanentFailureIds,
   263→    permanentFailureMessages: Array.from(permanentFailureMessages),
   264→    remaining,
   265→  };
   266→}
