    74→export function detectLowEndFromHints(hints: DeviceHints): boolean {
    75→  const ua = hints.userAgent.toLowerCase();
    76→  const memoryLow = hints.deviceMemoryGb !== null && hints.deviceMemoryGb <= 2;
    77→  const cpuLow = hints.hardwareConcurrency !== null && hints.hardwareConcurrency <= 4;
    78→  const networkLow = hints.effectiveType === "slow-2g" || hints.effectiveType === "2g";
    79→  const saveDataEnabled = hints.saveData === true;
    80→  const userAgentLow =
    81→    ua.includes("itel") || ua.includes("android go") || ua.includes("go edition") || ua.includes("infinix smart");
    82→  if (userAgentLow || memoryLow || networkLow || saveDataEnabled) return true;
    83→
    84→  const cpuOnlyLowSignal = cpuLow && hints.deviceMemoryGb === null && !ua.includes("android");
    85→  if (cpuOnlyLowSignal) return false;
    86→
    87→  return cpuLow;
    88→}
